    preferred = ", ".join(jd_config.get("preferred_skills", []))
    min_exp = jd_config.get("min_experience_years", "")
    pref_edu = jd_config.get("preferred_education", "")

    c_name = candidate_info.get("name", "Šť¬ščą")
    c_title = candidate_info.get("title", "Šť¬ščą")
    c_company = candidate_info.get("company", "Šť¬ščą")
    c_edu = candidate_info.get("education_level", "Šť¬ščą")
    c_years = candidate_info.get("work_years", "Šť¬ščą")
    c_skills = ", ".join(candidate_info.get("skills", [])) or "Šť¬ŠĆÉńżŤ"

    work_exp_text = ""
    for exp in candidate_info.get("work_experience", []):
        if isinstance(exp, dict):
            work_exp_text += f"- {exp.get('company', '')} | {exp.get('title', '')} | {exp.get('description', '')}\n"

    return f"""ńŻáŠś»ńŞÇńŻŹŔÁäŠĚ▒ŠŐÇŠť»ŠőŤŔüśńŞôň«ÂŃÇéŔ»ĚŠá╣ŠŹ«ŔüîńŻŹŠĆĆŔ┐░Ŕ»äń╝░ń╗ąńŞőňÇÖÚÇëń║║šÜäňî╣ÚůŹšĘőň║ŽŃÇé

## ŔüîńŻŹŠĆĆŔ┐░
- ŔüîńŻŹ: {jd_title}
- ŠĆĆŔ┐░: {jd_desc}
- ň┐ůňĄçŠŐÇŔâŻ: {required}
- ňŐáňłćŠŐÇŔâŻ: {preferred}
- ŠťÇńŻÄš╗ĆÚ¬î: {min_exp}ň╣┤
- ŠťčŠťŤňşŽňÄć: {pref_edu}

## ňÇÖÚÇëń║║ń┐íŠü»
- ňžôňÉŹ: {c_name}
- ňŻôňëŹŔüîńŻŹ: {c_title}
- ňŻôňëŹňůČňĆŞ: {c_company}
- ňşŽňÄć: {c_edu}
- ňĚąńŻťň╣┤ÚÖÉ: {c_years}
- ŠŐÇŔâŻŠáçšşż: {c_skills}
- ňĚąńŻťš╗ĆňÄć:
{work_exp_text or 'Šť¬ŠĆÉńżŤ'}

## Ŕ»äń╝░ŔŽüŠ▒é
š╗╝ňÉłŔÇâŔÖĹŠŐÇŔâŻňî╣ÚůŹň║ŽŃÇüš╗ĆÚ¬îšŤŞňů│ŠÇžŃÇüňşŽňÄćŔâîŠÖ»ŃÇüŔüîńŞÜňĆĹň▒ĽŔŻĘŔ┐╣´╝îš╗Öňç║0-100ňłćšÜäŔ»äňłćŃÇé

Ŕ»ĚńŞąŠá╝Šîëń╗ąńŞőJSONŠá╝ň╝ĆŔ┐öňŤ×´╝łńŞŹŔŽüňîůňÉźňůÂń╗ľňćůň«╣´╝ë:
{{"score": <0-100šÜäŠĽ┤ŠĽ░>, "explanation": "<ńŞÇňĆąŔ»ŁńŞşŠľçŔ»┤ŠśÄ>"}}"""


def _parse_llm_response(text: str) -> Optional[Dict[str, Any]]:
    """Parse LLM response with multiple fallback strategies."""
    if not text:
        return None

    # Strategy 1: Direct JSON parse
    try:
        result = json.loads(text.strip())
        if isinstance(result, dict) and "score" in result:
            return _validate_result(result)
    except json.JSONDecodeError:
        pass

    # Strategy 2: Extract from code block
    code_block = re.search(r"```(?:json)?\s*(\{.*?\})\s*```", text, re.DOTALL)
    if code_block:
        try:
            result = json.loads(code_block.group(1))
            if isinstance(result, dict) and "score" in result:
                return _validate_result(result)
        except json.JSONDecodeError:
            pass

    # Strategy 3: Find JSON object in text
    json_match = re.search(r"\{[^{}]*\"score\"\s*:\s*\d+[^{}]*\}", text)
    if json_match:
        try:
            result = json.loads(json_match.group(0))
            return _validate_result(result)
        except json.JSONDecodeError:
            pass

    # Strategy 4: Regex extract score number
    score_match = re.search(r"[\"']?score[\"']?\s*[:´╝Ü]\s*(\d+)", text)
    if score_match:
        score = int(score_match.group(1))
        explanation_match = re.search(r"[\"']?explanation[\"']?\s*[:´╝Ü]\s*[\"']([^\"']+)[\"']", text)
        explanation = explanation_match.group(1) if explanation_match else ""
        return _validate_result({"score": score, "explanation": explanation})

    logger.warning(f"Failed to parse LLM response: {text[:200]}")
    return None


def _validate_result(result: Dict[str, Any]) -> Optional[Dict[str, Any]]:
    """Validate and clamp the score."""
    try:
        score = int(result.get("score", -1))
        if 0 <= score <= 100:
            return {
                "score": score,
                "explanation": str(result.get("explanation", "")),
            }
    except (ValueError, TypeError):
        pass
    return None


def llm_score_candidate(
    candidate_info: Dict[str, Any],
    jd_config: Dict[str, Any],
    endpoint: str = "http://127.0.0.1:11434",
    model: str = "qwen2.5:7b",
    timeout_seconds: int = 60,
) -> Optional[Dict[str, Any]]:
    """Score a single candidate using Ollama LLM.

    Returns:
        {"score": 0-100, "explanation": "..."} or None on failure.
    """
    prompt = _build_scoring_prompt(candidate_info, jd_config)

    try:
        resp = httpx.post(
            f"{endpoint.rstrip('/')}/api/chat",
            json={
                "model": model,
                "messages": [{"role": "user", "content": prompt}],
                "stream": False,
                "options": {"temperature": 0.1},
            },
            timeout=timeout_seconds,
        )
        resp.raise_for_status()
        data = resp.json()
        content = data.get("message", {}).get("content", "")
        result = _parse_llm_response(content)
        if result:
            logger.debug(f"LLM scored {candidate_info.get('name', '?')}: {result['score']}")
        return result
    except Exception as e:
        logger.warning(f"LLM scoring failed for {candidate_info.get('name', '?')}: {e}")
        return None


def llm_score_candidates_batch(
    candidates_info: List[Dict[str, Any]],
    jd_config: Dict[str, Any],
    endpoint: str = "http://127.0.0.1:11434",
    model: str = "qwen2.5:7b",
    timeout_seconds: int = 60,
) -> List[Optional[Dict[str, Any]]]:
    """Score multiple candidates sequentially.

    Returns:
        List of results, same length as input. None for failed entries.
    """
    results = []
    for i, info in enumerate(candidates_info):
        logger.info(f"LLM scoring candidate {i+1}/{len(candidates_info)}: {info.get('name', '?')}")
        result = llm_score_candidate(info, jd_config, endpoint, model, timeout_seconds)
        results.append(result)
    return results

